export const catalogSectors = [...new Set(catalogCategoryDetails.map((category) => category.sector))];

export const getCatalogDetailsBySector = (sector: CatalogSector) =>
  catalogCategoryDetails.filter((category) => category.sector === sector);

export const getCatalogDetail = (sector: string, slug: string) =>
  catalogCategoryDetails.find((category) => category.sector === sector && category.slug === slug);

export const getCatalogReferenceFilters = (references: CatalogReference[]) =>
  [...new Set(references.map((reference) => reference.filter))];
